import { getAgentStatus } from '../utils';

export function statusCommand() {
  const status = getAgentStatus();
  console.log(`Agent: ${status.name}`);
  console.log(`State: ${status.state}`);
  console.log(`Uptime: ${status.uptime}s`);
}

import { statusCommand } from '../src/lib/commands/status';

describe('status command', () => {
  it('should print agent status without errors', () => {
    const consoleSpy = jest.spyOn(console, 'log').mockImplementation();
    statusCommand();
    expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Agent:'));
    consoleSpy.mockRestore();
  });
});
